interface.signature:
$api.useQuery('get', '/api/courses/{slug}/lessons', {
  params: { path: { slug: courseSlug } },
  refetchInterval: (query) => {
    const lessons = query.state.data?.lessons;
    const hasGenerating = lessons?.some(l => 
      l.status === 'SCRIPT_GENERATING' || l.status === 'AUDIO_GENERATING'
    );
    return hasGenerating ? 5000 : false;
  },
})

import { toast } from 'sonner';
toast.success(message: string): void
toast.error(message: string): void
